insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('sport-studies:5-1-4-technology-to-enhance-spectatorship:learn:9d1c83fb', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'learn', 'mcq', 1, '{"readingTitle": "Apps, live stats and applying examples correctly", "reading": "<h4>Live stats and second-screen apps</h4>\n<ul>\n<li>Fans can use official <strong>apps or websites</strong> during an event to check <strong>live statistics</strong> — such as a runner''s split times, a team''s possession percentage, or a player''s distance covered — while still watching the action.</li>\n<li>This adds detail the naked eye cannot supply, and lets a fan away from the venue feel closer to the event.</li>\n</ul>\n<h4>Always name a sport or setting</h4>\n<ul>\n<li>Weak answer: <em>\"Technology helps spectators.\"</em> That names a role but gives no detail.</li>\n<li>Strong answer: <em>\"A big screen at a rugby stadium replays a disputed try in slow motion, so fans can see the evidence and understand the referee''s decision, instead of only hearing an announcement.\"</em></li>\n<li>The mark almost always needs a <strong>named example linked to a specific benefit</strong> — not just the word \"technology\".</li>\n</ul>\n<h4>Don''t confuse this with the evaluation topic</h4>\n<ul>\n<li>This topic is about how technology is <strong>used</strong> to improve the spectator experience. A different topic asks you to <strong>weigh up</strong> the positives and negatives of technology for spectators — save that judgement for that topic, and focus here on explaining clear uses and benefits.</li>\n</ul>", "question": "A strong exam answer about enhancing spectatorship should always include...", "options": ["A named example of the technology linked to a specific benefit for fans", "The word ''technology'' repeated as many times as you possibly can manage", "A criticism of an official''s overall performance in the fixture", "A description of a performer''s personal training programme"]}'::jsonb, '{"answer": 0, "explain": "Naming the technology and linking it to a real benefit for the audience is what earns marks — repeating a word, criticising officials, or describing training is off-topic here."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:misc:834f8d79', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If spectators can see it happening, it must be an example of technology enhancing spectatorship.</p><p><strong>✅ The correct idea:</strong> The test is not whether spectators can SEE it — it''s whether the technology''s main purpose is to improve the watching experience. A goal-line sensor is visible to the crowd, but its purpose is helping the official make a correct call, so it belongs with officiating, not spectatorship. Ask: ''who is this mainly FOR — the crowd, or the official?''</p>", "question": "A goal-line sensor confirms the ball crossed the line for the referee. Even though the crowd can see the outcome, this is best classed as...", "options": ["technology enhancing spectatorship", "technology supporting officiating", "technology enhancing performance", "technology increasing participant safety"]}'::jsonb, '{"answer": 1, "explain": "Its main purpose is giving the official correct information, so it belongs with officiating, even though the crowd can also see the result."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:misc:4428808a', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Naming ''big screens'' is enough to answer any question about enhancing spectatorship.</p><p><strong>✅ The correct idea:</strong> Naming the technology is only the first step. The mark almost always needs the SPECIFIC benefit linked to it — what the screen actually shows, and why that helps fans. ''Big screens'' alone earns little; ''a big screen replays a disputed decision so the crowd can follow it'' earns the mark.</p>", "question": "Which answer about big screens is most likely to earn full marks?", "options": ["Big screens exist inside most modern stadiums built all around the world today", "A big screen replays a review so the crowd can follow the decision", "Big screens are usually very large and extremely bright", "Some large stadiums have more than one big screen"]}'::jsonb, '{"answer": 1, "explain": "Only this option links the technology to a specific benefit for the audience — the others just describe the screen."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:misc:93a34cf3', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> This topic is the same as weighing up the positives and negatives of technology for fans.</p><p><strong>✅ The correct idea:</strong> This topic is about how technology is USED to enhance the experience — explaining benefits with named examples. Weighing up both the positives AND the negatives for spectators is a separate, later topic. Keep this topic focused on clear, positive uses.</p>", "question": "A question on THIS topic mainly wants you to...", "options": ["explain positive uses of technology for spectators with examples", "list every possible negative effect on spectators in a great deal of detail", "describe a performer''s personal training schedule", "weigh up the costs and benefits of officiating technology only"]}'::jsonb, '{"answer": 0, "explain": "This topic focuses on explaining enhancement/uses with named examples; weighing positives and negatives together belongs to a separate topic."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:tips:b6ce9d57', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Questions on enhancing spectatorship are usually short recall or short explain. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name a piece of technology. \"Identify one way technology enhances spectatorship\" = one named example. 1 mark.</li>\n<li><strong>Describe</strong> — say what the technology does. \"Describe how big screens are used\" = explain what appears on the screen.</li>\n<li><strong>Explain</strong> — give a reason, using \"because\". \"Explain how this benefits spectators\" = the use PLUS why it helps the audience.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed with a reason; [4] in Section B wants points applied to the scenario given.</p>", "question": "A question says: ''Identify one piece of technology that enhances spectatorship [1]''. What is the safest answer?", "options": ["One named example, such as a big screen replay", "A long paragraph describing several different technologies", "A description of how an official reviews a decision", "An explanation of a performer''s diet and training"]}'::jsonb, '{"answer": 0, "explain": "''Identify'' + [1] wants one named example — nothing about officiating, training or a lengthy paragraph is needed."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:tips:9e5bf641', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the technology AND the benefit", "reading": "<p>The single most common way to lose marks here is naming the technology with no benefit attached. Build every answer as <strong>technology → what it shows/does → benefit for the fan</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Big screens.\"</li>\n<li><strong>✅ full marks:</strong> \"A big screen replays a disputed try in slow motion, so fans in the stadium can see the evidence and follow the referee''s decision.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named venue, a named event). Use a detail <em>from that scenario</em>, not a general example.</p>", "question": "In a Section B scenario about a named stadium, your example of enhancing spectatorship should come from...", "options": ["any technology you happen to have heard of before", "the scenario you are given", "a completely different sport entirely", "your own personal opinion of the stadium"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — marks come from using the scenario given, not a random unrelated example."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:tips:e82f265d', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> enhancing spectatorship appears as quick recall in <strong>Section A</strong> (identify/describe a technology), and as applied points in <strong>Section B</strong> scenarios about a venue or event upgrading its technology. It can also feed a <strong>Section C</strong> 8-mark discussion of how technology affects the wider spectator experience.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Split your examples into \"inside the venue\" (big screens, replays) and \"away from the venue\" (broadcast graphics, apps) so you always have more than one type ready.</li>\n<li>Always name a sport or setting — a vague \"technology helps fans\" answer earns little.</li>\n<li>Keep this topic about uses and benefits; save weighing up downsides for the evaluation topic.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One example of technology enhancing spectatorship is… because…\"</li>\n<li>\"This benefits fans by…\"</li>\n<li>\"However, the same technology might not help every fan, because…\"</li>\n</ul>", "question": "Splitting examples into ''inside the venue'' and ''away from the venue'' mainly helps because...", "options": ["it guarantees full marks on every single question you attempt", "it gives you more than one type of example ready to use", "it means you never need to give a named example", "it replaces the need to explain any benefit at all"]}'::jsonb, '{"answer": 1, "explain": "Having both types ready means you can answer whichever setting a question describes, with a specific example rather than a vague one."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:fib:44499233', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'fib', 'fib', 1, '{"question": "Spectatorship means the experience of _____ sport, whether live or on a screen.", "blankOptions": {"B1": ["watching", "angles", "graphics", "replay"]}}'::jsonb, '{"blanks": {"B1": "watching"}}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:fib:111aecd9', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'fib', 'fib', 1, '{"question": "A big screen inside a stadium can show fans an action _____ so they can see a moment again.", "blankOptions": {"B1": ["replay", "watching", "angles", "graphics"]}}'::jsonb, '{"blanks": {"B1": "replay"}}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:fib:26e7ba1a', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'fib', 'fib', 1, '{"question": "Broadcasters add on-screen _____ to give viewers extra information, such as a speed reading.", "blankOptions": {"B1": ["angles", "replay", "graphics", "watching"]}}'::jsonb, '{"blanks": {"B1": "graphics"}}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:fib:6cf20c89', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'fib', 'fib', 1, '{"question": "Multiple camera _____ let broadcast viewers see an incident from more than one view.", "blankOptions": {"B1": ["watching", "graphics", "replay", "angles"]}}'::jsonb, '{"blanks": {"B1": "angles"}}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:fib:2a0fd7fd', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'fib', 'fib', 1, '{"question": "A live-stats _____ lets a fan check extra statistics, such as split times, during an event.", "blankOptions": {"B1": ["app", "replay", "watching", "graphics"]}}'::jsonb, '{"blanks": {"B1": "app"}}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:match:41f19fa1', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Spectatorship”?", "options": ["Footage played back at reduced speed so viewers can study a fast incident more clearly", "On-screen information added to a TV picture, such as a trajectory line or a speed reading", "An app or website giving fans extra statistics, such as split times, during an event", "The experience of watching sport, either live in a venue or through broadcast and apps"]}'::jsonb, '{"answer": 3, "explain": "“Spectatorship” means: The experience of watching sport, either live in a venue or through broadcast and apps"}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:match:3b387101', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Big screen”?", "options": ["Large screen fitted inside a stadium or arena, used to show fans replays and review decisions", "Footage played back at reduced speed so viewers can study a fast incident more clearly", "Several different broadcast views of the same incident, shown so viewers see more detail", "An app or website giving fans extra statistics, such as split times, during an event"]}'::jsonb, '{"answer": 0, "explain": "“Big screen” means: Large screen fitted inside a stadium or arena, used to show fans replays and review decisions"}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:match:40610ab9', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Broadcast graphics”?", "options": ["An app or website giving fans extra statistics, such as split times, during an event", "On-screen information added to a TV picture, such as a trajectory line or a speed reading", "Several different broadcast views of the same incident, shown so viewers see more detail", "The experience of watching sport, either live in a venue or through broadcast and apps"]}'::jsonb, '{"answer": 1, "explain": "“Broadcast graphics” means: On-screen information added to a TV picture, such as a trajectory line or a speed reading"}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:match:c5735141', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Multiple camera angles”?", "options": ["On-screen information added to a TV picture, such as a trajectory line or a speed reading", "The experience of watching sport, either live in a venue or through broadcast and apps", "An app or website giving fans extra statistics, such as split times, during an event", "Several different broadcast views of the same incident, shown so viewers see more detail"]}'::jsonb, '{"answer": 3, "explain": "“Multiple camera angles” means: Several different broadcast views of the same incident, shown so viewers see more detail"}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:match:6490f00c', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Live-stats app”?", "options": ["Footage played back at reduced speed so viewers can study a fast incident more clearly", "Large screen fitted inside a stadium or arena, used to show fans replays and review decisions", "An app or website giving fans extra statistics, such as split times, during an event", "Several different broadcast views of the same incident, shown so viewers see more detail"]}'::jsonb, '{"answer": 2, "explain": "“Live-stats app” means: An app or website giving fans extra statistics, such as split times, during an event"}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:match:e61fc373', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Slow-motion replay”?", "options": ["An app or website giving fans extra statistics, such as split times, during an event", "The experience of watching sport, either live in a venue or through broadcast and apps", "Footage played back at reduced speed so viewers can study a fast incident more clearly", "Several different broadcast views of the same incident, shown so viewers see more detail"]}'::jsonb, '{"answer": 2, "explain": "“Slow-motion replay” means: Footage played back at reduced speed so viewers can study a fast incident more clearly"}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:exam:e55dde04', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is an example of technology producing a positive effect through ''more accurate decisions''?", "options": ["A GPS vest recording a rugby player''s total distance covered in a session", "Ball-tracking technology confirming exactly where a tennis ball landed", "A cryotherapy chamber reducing swelling in the days after an injury", "Video footage helping a coach spot a small flaw in a swimmer''s stroke"], "hint": "Think about which option gives officials evidence the eye alone can miss.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Ball-tracking technology confirming exactly where a tennis ball landed.</strong></p>\n<ul>\n<li>This gives an official evidence the eye alone can miss, so the correct decision is reached more often.</li>\n<li>The other options show enhanced performance, quicker recovery, and technical analysis instead.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:mcq:9718fc83', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'mcq', 'mcq', 1, '{"question": "A cyclist uses a power meter to see the exact wattage they produce on a climb. Which positive effect of technology does this best show?", "options": ["More accurate decisions, because the power meter overturns any decision an official makes in a road race", "Quicker recovery from injury, because the power meter treats sore muscles after every training ride", "Enhanced performance, because training can now target the exact weakness the wattage data reveals", "Technical analysis, because the power meter replaces the need for a coach to ever watch the rider"]}'::jsonb, '{"answer": 2, "explain": "Seeing exact wattage lets training target a genuine weakness, which is enhanced performance. A power meter does not overturn decisions, treat muscles, or replace a coach."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:mcq:645b1a88', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'mcq', 'mcq', 1, '{"question": "A rugby player wears an impact-sensing mouthguard that records the force of collisions. Which positive effect does this best show?", "options": ["Technical analysis, because the mouthguard automatically studies and redesigns the player''s entire long-term training programme", "Lower risk of injury, because the recorded force can prompt a medical check before a visible symptom appears", "More accurate decisions, because the mouthguard decides every refereeing call made during the match", "Enhanced performance, because wearing the mouthguard alone guarantees the player will run faster"]}'::jsonb, '{"answer": 1, "explain": "Flagging dangerous force lets staff check a player before symptoms show — that lowers injury risk. It does not redesign training, referee, or guarantee speed."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:mcq:67c42057', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'mcq', 'mcq', 1, '{"question": "After surgery, a footballer uses a cryotherapy chamber and an underwater treadmill during rehabilitation. Which positive effect does this best show?", "options": ["Enhanced performance, because the treadmill instantly and permanently makes the footballer much better than before the injury ever happened", "More accurate decisions, because the chamber overturns the referee''s original decision from the match", "Technical analysis, because this equipment films the footballer''s stroke technique frame by frame", "Quicker recovery from injury, because the cold reduces swelling and the treadmill keeps fitness moving safely"]}'::jsonb, '{"answer": 3, "explain": "Cold reducing swelling plus safe, protected fitness work is quicker recovery from injury — not instant improvement, a reversed decision, or filmed technique."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:mcq:cce5f5c2', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'mcq', 'mcq', 1, '{"question": "A cricket umpire uses ball-tracking technology to check whether a batter would have been out. Which positive effect does this best show?", "options": ["More accurate decisions, because the technology gives evidence of the ball''s path that the eye alone can miss", "Quicker recovery from injury, because the tracking technology instantly and completely heals any injury the batter currently happens to have", "Enhanced performance, because the tracking data alone will make the batter score more runs next innings", "Technical analysis, because the umpire uses the footage to completely redesign the batter''s technique"]}'::jsonb, '{"answer": 0, "explain": "Ball-tracking gives evidence the eye can miss, so the correct decision is reached more often — that is more accurate decisions, not healing, scoring, or redesigning technique."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:mcq:0d944756', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'mcq', 'mcq', 1, '{"question": "A swimming coach films a swimmer''s stroke and studies it frame by frame after every session. Which positive effect does this best show?", "options": ["More accurate decisions, because the footage can completely change the result of a race that has already finished and been announced", "Lower risk of injury, because filming a swimmer''s stroke prevents every possible muscle strain", "Technical analysis, because the coach can spot a small technical flaw that is hard to see live at full speed", "Enhanced performance, because owning a camera alone raises how fast the swimmer can swim"]}'::jsonb, '{"answer": 2, "explain": "Studying video closely to spot a precise flaw is technical analysis — footage does not change a finished result, prevent all strains, or speed a swimmer up by itself."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:mcq:a4145cd4', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'mcq', 'mcq', 1, '{"question": "Which of these describes something that is NOT one of the five positive effects covered on this page?", "options": ["Enhanced performance from a coach using detailed session data", "More accurate decisions made using ball-tracking or video-review technology", "Reduced flow of the game while officials stop to check a replay screen", "Quicker recovery from injury after treatment in a cryotherapy chamber"]}'::jsonb, '{"answer": 2, "explain": "A slower, more stop-start game is a downside of technology, not a positive effect — the other three options are all on this page''s list of five positive effects."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:tf:9eb31353', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'tf', 'tf', 1, '{"question": "Technology can give coaches exact data, such as distance or speed, that the human eye cannot collect alone."}'::jsonb, '{"answer": true, "explain": "That data is exactly what lets training target a performer''s real weakness — the basis of enhanced performance."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:tf:8bdb3101', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'tf', 'tf', 1, '{"question": "Wearable sensors can only be used to punish a performer after an injury has already happened."}'::jsonb, '{"answer": false, "explain": "Sensors can flag dangerous forces BEFORE an injury, prompting a medical check early — that helps prevent harm, not just react to it."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:tf:726b58e2', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'tf', 'tf', 1, '{"question": "A cryotherapy chamber is an example of technology helping a performer recover more quickly from injury."}'::jsonb, '{"answer": true, "explain": "The extreme cold can reduce swelling and pain in the days after an injury, supporting a quicker, safer recovery."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:tf:0b74b39e', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'tf', 'tf', 1, '{"question": "Ball-tracking and video-review technology can never make an officiating decision more accurate."}'::jsonb, '{"answer": false, "explain": "It gives evidence the human eye can miss, so the correct decision is reached more often — that IS more accurate decisions."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:tf:2307f8c7', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'tf', 'tf', 1, '{"question": "Technical analysis means using data or video to study technique closely, rather than relying on memory alone."}'::jsonb, '{"answer": true, "explain": "That is the definition — frame-by-frame footage or measurements reveal detail a coach''s memory of the session cannot."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:tf:c3858f40', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'tf', 'tf', 1, '{"question": "A strong exam answer about a positive effect only needs to name the effect, with no explanation or example."}'::jsonb, '{"answer": false, "explain": "Naming the effect earns little on its own — full marks need HOW the technology produces it and a named sporting example."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:learn:fccb43d8', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'learn', 'mcq', 1, '{"readingTitle": "Enhanced performance and a lower risk of injury", "reading": "<h4>Enhanced performance</h4>\n<ul>\n<li>Technology can give performers and coaches <strong>precise data</strong> that the human eye simply cannot collect — for example, a <strong>GPS vest</strong> worn by a rugby player records exact distance covered, sprint speed and how hard each session was.</li>\n<li>Because training can then target the <em>real</em> weakness shown by the data, rather than a coach''s guess, performance improves faster than it would through trial and error.</li>\n<li>A cyclist using a <strong>power meter</strong> can see the exact wattage they are producing on a climb, so the next session is planned around a genuine number instead of how tired their legs feel.</li>\n</ul>\n<h4>Lower risk of injury</h4>\n<ul>\n<li>Wearable sensors can flag dangerous forces before they cause an injury. A rugby player''s <strong>impact-sensing mouthguard</strong> can record the force of a collision, so medical staff know when to check a player over rather than waiting for a visible symptom.</li>\n<li>Better-designed protective equipment — closer-fitting boots, padded headguards — reduces the chance that a normal knock in a contact sport turns into a serious injury.</li>\n<li>Together, this means technology does not just react to injuries; it helps <strong>prevent</strong> some from happening at all.</li>\n</ul>", "question": "Which of these best explains how a GPS vest could lead to ''enhanced performance''?", "options": ["It gives an exact number for things like distance and speed, so training can target the real weakness it shows", "It automatically and permanently raises the total wages a professional performer is paid by their club every season", "It stops every player at the club from ever picking up an injury again in future", "It plays calming music to the performer throughout a match to help them relax"]}'::jsonb, '{"answer": 0, "explain": "A GPS vest measures genuine performance data (distance, speed, effort), letting training target the actual weakness it reveals — not wages, an injury guarantee, or music."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:learn:fdea93e1', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'learn', 'mcq', 1, '{"readingTitle": "Quicker recovery from injury and more accurate decisions", "reading": "<h4>Quicker recovery from injury</h4>\n<ul>\n<li>When a performer IS injured, technology can speed up a safe return. A <strong>cryotherapy chamber</strong> exposes the body to extreme cold for a short time, which can reduce swelling and pain in the days straight after an injury.</li>\n<li><strong>Compression garments</strong> and underwater treadmills let an injured performer keep some fitness and blood flow moving while the injury itself is still protected.</li>\n<li>Medical staff can also track healing with scans and data instead of guesswork, so a performer returns to full training when the evidence says they are ready — not simply when they say they \"feel fine.\"</li>\n</ul>\n<h4>More accurate decisions</h4>\n<ul>\n<li>Ball-tracking and video-review technology gives officials evidence a human eye alone can miss. In tennis, a line-calling system can show whether a ball landed a few millimetres in or out; in football, goal-line technology confirms whether the whole ball crossed the line.</li>\n<li>Because the correct decision is reached more often, the result of the contest is fairer to both sides — settling an argument over a mistaken call that technology could resolve instantly.</li>\n</ul>", "question": "Why can ball-tracking or goal-line technology lead to ''more accurate decisions''?", "options": ["It gives officials clear evidence the naked eye can miss, so the correct decision is reached more often", "It removes the need for a match official to be present at the fixture at all", "It always makes the crowd cheer louder for the home team throughout the fixture", "It guarantees that every single decision from now on will always favour whichever team is currently losing"]}'::jsonb, '{"answer": 0, "explain": "Ball-tracking gives evidence the eye can miss, so officials reach the correct decision more often — it does not remove officials, sway crowds, or favour a team."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:learn:d0860f00', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'learn', 'mcq', 1, '{"readingTitle": "Technical analysis — and explaining a positive effect fully", "reading": "<h4>Technical analysis</h4>\n<ul>\n<li><strong>Technical analysis</strong> means using data or video to study a performer''s technique closely, so a coach can see exactly what to change instead of relying on memory of what happened.</li>\n<li>Filming a swimmer''s stroke, then reviewing it frame by frame, can reveal a small technical flaw — such as an early arm entry — that would be almost impossible to spot live, at full speed, from the poolside.</li>\n<li>Combining video with data such as heart rate or stride length gives an even fuller picture, so feedback to the performer is specific rather than a vague impression.</li>\n</ul>\n<h4>Explaining a positive effect fully — the exam skill</h4>\n<ul>\n<li>A weak answer just names an effect: <em>\"Technology helps with recovery.\"</em> A strong answer names the effect, says HOW the technology produces it, and gives a named sporting example.</li>\n<li>Strong version: <em>\"A cryotherapy chamber can speed up recovery from injury, because the extreme cold reduces swelling in the days straight after the injury happens — for example for an injured rugby player.\"</em></li>\n<li>Keep five positive effects ready to draw on: enhanced performance, lower risk of injury, quicker recovery from injury, more accurate decisions, and technical analysis.</li>\n</ul>", "question": "What makes an exam answer about a positive effect of technology ''full'', rather than basic?", "options": ["Naming the effect, explaining how the technology produces it, and giving a named sporting example", "Simply writing down the name of one piece of sports technology", "Listing as many different pieces of sports technology as you possibly can fit onto the entire page", "Describing your own personal opinion of a professional sports team"]}'::jsonb, '{"answer": 0, "explain": "Full marks come from naming the effect, explaining HOW it happens, and applying it to a sporting example — not a bare name, a long list, or an opinion."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:misc:922c88c6', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If I just name a positive effect, like ''enhanced performance'', that is enough for the marks.</p><p><strong>✅ The correct idea:</strong> Naming the effect is usually only the first mark, if that. The examiner wants you to explain HOW the technology produces the effect, ideally with a named sporting example. Basic answer: \"Technology gives enhanced performance.\" Full-marks answer: \"A GPS vest gives a rugby player exact distance and speed data, so training can target their real weakness — enhancing performance.\" The difference is the explanation and the example.</p>", "question": "An ''Explain'' question asks how technology produces a positive effect. What earns the marks?", "options": ["Naming as many different pieces of sports technology as you can possibly remember", "Naming the effect, then explaining HOW the technology produces it", "Writing the effect''s name in a longer sentence", "Describing your own favourite sports team"]}'::jsonb, '{"answer": 1, "explain": "Explain = effect + mechanism (how it happens). Naming technology or lengthening the same sentence without a mechanism does not show the understanding the mark scheme rewards."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:misc:fdb72e94', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Technical analysis'' just means a coach watching the match normally, the same as always.</p><p><strong>✅ The correct idea:</strong> Normal watching, at full speed and from a distance, is exactly what technical analysis improves on. It specifically means using video or data — reviewed frame by frame, or measured precisely — to spot a detail (like an early arm entry) that live watching would miss. If your answer could describe any coach on any touchline, it has not shown technical analysis.</p>", "question": "What is the key difference between ''technical analysis'' and simply watching a match live?", "options": ["There is no real difference at all between the two things, they are exactly the same idea", "Technical analysis studies video or data closely to spot detail live watching would miss", "Technical analysis means a coach stops watching matches completely", "Technical analysis only ever happens after a performer retires"]}'::jsonb, '{"answer": 1, "explain": "Technical analysis uses close, repeatable study (frame by frame, or measured data) to catch detail that live, full-speed watching cannot — that precision is the whole point."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:misc:a749ffd7', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''More accurate decisions'' and ''quicker decisions'' mean exactly the same thing.</p><p><strong>✅ The correct idea:</strong> They are different ideas. ''More accurate'' means the correct decision is reached more often, because officials have better evidence. It says nothing about speed — reviewing footage can even take longer than a snap judgement. Don''t swap ''accurate'' for ''quick'' in an answer; they test different understanding.</p>", "question": "Why is ''more accurate decisions'' a different claim from ''quicker decisions''?", "options": ["Accuracy is about reaching the correct decision, which is separate from how fast it is reached", "A quick decision is always the same thing as a correct decision", "Accurate decisions can only ever be reached completely instantly, and never at all after any kind of review", "There is no meaningful difference between accuracy and speed"]}'::jsonb, '{"answer": 0, "explain": "Accuracy is about correctness, not speed — a review can be slower yet still more accurate, so the two ideas must not be confused in an answer."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:tips:c5cce914', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — matching your answer to the tariff", "reading": "<p>Positive-effects questions can be short recall or longer applied writing. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name the effect. \"Identify one positive effect of technology\" = write its name. 1 mark.</li>\n<li><strong>Describe</strong> — say what the technology does. \"Describe how a cryotherapy chamber helps a performer\" = describe the process.</li>\n<li><strong>Explain</strong> — give the mechanism. Use the word <em>because</em>. \"Explain how video analysis benefits a swimmer\" = the effect PLUS how it happens.</li>\n<li><strong>Discuss / Evaluate</strong> — weigh positives against a limit or a negative, then reach a judgement (usually 6 or 8 marks).</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] usually wants two effects applied to a scenario; [6]/[8] level-of-response wants balance and a justified judgement.</p>", "question": "A question says: ''Explain one positive effect that technology can have on a performer''s recovery. [2]'' What is the safest structure?", "options": ["Name a piece of technology only, with absolutely no further detail given at all", "Name the effect, then explain how the technology produces it", "List every positive effect you can remember", "Describe an unrelated piece of sports equipment"]}'::jsonb, '{"answer": 1, "explain": "''Explain'' + [2] rewards a mechanism, not just a name. Listing several effects or describing something unrelated wastes the two marks on offer."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:tips:9c993565', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the effect, explain how, then give an example", "reading": "<p>The single most common way to lose marks here is stopping at the effect''s name. Build every answer as <strong>effect → mechanism → sporting example</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Technology helps with recovery.\"</li>\n<li><strong>✅ full marks:</strong> \"A cryotherapy chamber speeds up recovery from injury, because the extreme cold reduces swelling in the days after the injury happens — for example for an injured rugby player.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named club, a named piece of technology). You must then use a detail <em>from that scenario</em>, not a generic example.</p>", "question": "In a Section B scenario about a named club buying named technology, your explanation should be built around...", "options": ["any sport that you personally happen to enjoy watching in your own free time", "the specific technology and scenario you are given", "a famous athlete unrelated to the scenario", "your own school''s PE lessons only"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for using the scenario''s own technology and detail. A generic example that ignores the scenario is capped."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:tips:4980f8e4', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this topic appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> positive effects appear as quick recall in <strong>Section A</strong> (identify/explain), as applied points in <strong>Section B</strong> scenarios about a club or performer using new technology, and they feed <strong>Section C</strong> 8-mark Discuss/Evaluate answers weighing technology''s positives against its costs or limits.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Keep all five effects ready: enhanced performance, lower risk of injury, quicker recovery, more accurate decisions, technical analysis.</li>\n<li>For every effect, memorise one worked mechanism (like the cryotherapy example) so you always have a full sentence ready.</li>\n<li>In a longer answer, don''t just list effects — pick two or three and develop each one properly.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One positive effect here is… because…\"</li>\n<li>\"This benefits the performer by… which shows…\"</li>\n<li>\"However, this benefit depends on… so overall…\"</li>\n</ul>", "question": "Why is it better to develop two or three positive effects properly than to list five?", "options": ["Listing five effects by name is always worth far more marks than developing just two of them", "A developed explanation with a mechanism earns more than a bare list of names", "The exam only ever allows one effect to be mentioned", "Developing an effect means giving your personal opinion instead"]}'::jsonb, '{"answer": 1, "explain": "Marks come from mechanism and application, not from how many names appear — two well-developed effects out-score five bare names."}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:fib:aeec03ab', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'fib', 'fib', 1, '{"question": "Detailed training data can help target a performer''s weakness, which is a form of enhanced _____.", "blankOptions": {"B1": ["recovery", "accurate", "performance", "analysis"]}}'::jsonb, '{"blanks": {"B1": "performance"}}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:fib:36b5bf00', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'fib', 'fib', 1, '{"question": "Sensors that flag dangerous forces early can help lower the risk of _____.", "blankOptions": {"B1": ["performance", "injury", "accurate", "recovery"]}}'::jsonb, '{"blanks": {"B1": "injury"}}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:fib:34e061b8', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'fib', 'fib', 1, '{"question": "A cryotherapy chamber can reduce swelling, helping a performer make a quicker _____ from injury.", "blankOptions": {"B1": ["recovery", "performance", "analysis", "accurate"]}}'::jsonb, '{"blanks": {"B1": "recovery"}}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:fib:5b37eb58', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'fib', 'fib', 1, '{"question": "Ball-tracking technology gives officials evidence a human eye can miss, leading to more _____ decisions.", "blankOptions": {"B1": ["performance", "analysis", "accurate", "injury"]}}'::jsonb, '{"blanks": {"B1": "accurate"}}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:fib:210ef8d5', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'fib', 'fib', 1, '{"question": "Studying video or data closely to see exactly what to change is called technical _____.", "blankOptions": {"B1": ["performance", "analysis", "accurate", "recovery"]}}'::jsonb, '{"blanks": {"B1": "analysis"}}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:match:1ec23fab', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Enhanced performance”?", "options": ["Ball-tracking or video review gives officials evidence a human eye alone can miss", "Sensors and improved kit can flag danger early or reduce the harm of a normal knock", "Treatments such as extreme cold or protected exercise help someone return to fitness sooner", "Training data lets a performer or coach target a genuine weakness rather than guessing"]}'::jsonb, '{"answer": 3, "explain": "“Enhanced performance” means: Training data lets a performer or coach target a genuine weakness rather than guessing"}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:match:bf4b7570', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Lower risk of injury”?", "options": ["Sensors and improved kit can flag danger early or reduce the harm of a normal knock", "A wearable device that records a performer''s distance covered, speed and effort in a session", "Training data lets a performer or coach target a genuine weakness rather than guessing", "Treatments such as extreme cold or protected exercise help someone return to fitness sooner"]}'::jsonb, '{"answer": 0, "explain": "“Lower risk of injury” means: Sensors and improved kit can flag danger early or reduce the harm of a normal knock"}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:match:10a8a7dd', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quicker recovery”?", "options": ["Treatments such as extreme cold or protected exercise help someone return to fitness sooner", "Training data lets a performer or coach target a genuine weakness rather than guessing", "Sensors and improved kit can flag danger early or reduce the harm of a normal knock", "A wearable device that records a performer''s distance covered, speed and effort in a session"]}'::jsonb, '{"answer": 0, "explain": "“Quicker recovery” means: Treatments such as extreme cold or protected exercise help someone return to fitness sooner"}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:match:c64eee05', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “More accurate decisions”?", "options": ["Treatments such as extreme cold or protected exercise help someone return to fitness sooner", "Training data lets a performer or coach target a genuine weakness rather than guessing", "Studying video or data closely to see exactly what a technique needs to change", "Ball-tracking or video review gives officials evidence a human eye alone can miss"]}'::jsonb, '{"answer": 3, "explain": "“More accurate decisions” means: Ball-tracking or video review gives officials evidence a human eye alone can miss"}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:match:e1878719', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Technical analysis”?", "options": ["Studying video or data closely to see exactly what a technique needs to change", "Sensors and improved kit can flag danger early or reduce the harm of a normal knock", "Training data lets a performer or coach target a genuine weakness rather than guessing", "Ball-tracking or video review gives officials evidence a human eye alone can miss"]}'::jsonb, '{"answer": 0, "explain": "“Technical analysis” means: Studying video or data closely to see exactly what a technique needs to change"}'::jsonb),
('sport-studies:5-2-1-positive-effects-of-technology:match:6b490f6e', 'sport-studies', 'sport-studies:5-2-1-positive-effects-of-technology', '5.2.1 Positive Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “GPS vest”?", "options": ["Training data lets a performer or coach target a genuine weakness rather than guessing", "Sensors and improved kit can flag danger early or reduce the harm of a normal knock", "A wearable device that records a performer''s distance covered, speed and effort in a session", "Studying video or data closely to see exactly what a technique needs to change"]}'::jsonb, '{"answer": 2, "explain": "“GPS vest” means: A wearable device that records a performer''s distance covered, speed and effort in a session"}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:exam:f7bfb622', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these best describes a negative effect of officiating technology on the flow of a game?", "options": ["It can cause stoppages that interrupt the rhythm and momentum of play", "It guarantees the crowd will always enjoy the fixture more than before", "It removes every official from the fixture completely and permanently", "It makes the game finish in exactly half its normal running time"], "hint": "Think about what happens to play while a review is being checked.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — It can cause stoppages that interrupt the rhythm and momentum of play.</strong></p>\n<ul>\n<li>Checking a decision takes time, and that pause is the \"reduced flow\" problem.</li>\n<li>The other options overstate or misdescribe what officiating technology actually does.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:mcq:a4f00a3b', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'mcq', 'mcq', 1, '{"question": "Why might a wealthy national team gain an advantage purely from technology?", "options": ["Because expensive new equipment is often only affordable to well-funded teams or nations", "Because officials are told to favour whichever team owns the most technology", "Because technology automatically disqualifies any team that cannot afford it", "Because poorer nations are officially banned by every governing body''s written rules from using such equipment"]}'::jsonb, '{"answer": 0, "explain": "Cost is the barrier — a wealthy team can buy an edge that a poorer one simply cannot afford, which is the unequal-access problem, not a rule or an official''s bias."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:mcq:659f7f5a', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'mcq', 'mcq', 1, '{"question": "A small athletics club cannot get access to a biomechanics lab because almost no supplier offers one outside elite programmes. This is best described as a problem of...", "options": ["motivation, since the athletes involved are simply not trying hard enough to go and find one anywhere nearby", "availability, because the technology is not obtainable at that level regardless of funding", "rule-breaking, because using such labs is against the sport''s official rules", "officiating, because referees control who is allowed to use training technology"]}'::jsonb, '{"answer": 1, "explain": "When a technology simply is not offered or accessible at a level, that is an availability problem, separate from cost (affordability) or rules."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:mcq:193624fa', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'mcq', 'mcq', 1, '{"question": "Which of these is a genuine downside of officials using video review technology?", "options": ["It can slow the game down and reduce its natural flow while the check takes place", "It makes every single decision instantly and with absolutely no delay whatsoever", "It removes the need for any officials to be present at a fixture ever again", "It guarantees every decision will always be perfectly correct with no possible dispute"]}'::jsonb, '{"answer": 0, "explain": "Reviews take time, and that pause interrupts the rhythm of the contest — the other options overstate what the technology actually delivers."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:mcq:c008aa85', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'mcq', 'mcq', 1, '{"question": "What does it mean if an official becomes ''over-influenced'' by technology?", "options": ["They ignore the technology completely and always trust their own on-field judgement over it instead", "They treat the technology''s output as automatically correct, even outside its real limits", "They ask a second official to make every single decision instead of using any technology", "They stop the fixture permanently until new equipment can be purchased and installed"]}'::jsonb, '{"answer": 1, "explain": "Over-reliance means trusting the technology as final even in situations where it may not give the best interpretation of the rules."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:mcq:12509845', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'mcq', 'mcq', 1, '{"question": "As sports technology advances, what typically happens to its cost over time?", "options": ["It falls so quickly and so reliably that every grassroots club can easily afford it within just a year", "It usually stays high or keeps rising, since newer versions cost more to develop", "It becomes completely free once a governing body approves it for use", "It has no relationship at all with how advanced or recent the technology is"]}'::jsonb, '{"answer": 1, "explain": "Advancing technology tends to keep costs high or rising, which is part of why affordability remains a recurring problem for smaller clubs."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:mcq:1919b941', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'mcq', 'mcq', 1, '{"question": "A rugby TMO review pauses play for over a minute during an attacking passage of play. This mainly illustrates...", "options": ["greatly improved availability of officiating technology reaching every single grassroots level fixture", "reduced flow of the game caused by an officiating stoppage", "unequal access between two professional teams", "the complete removal of the on-field referee''s authority"]}'::jsonb, '{"answer": 1, "explain": "The stoppage interrupts the momentum of play, which is exactly what ''reduced flow of the game'' describes."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:tf:9068068b', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'tf', 'tf', 1, '{"question": "New sports technology is usually expensive, which can create unequal access between wealthier and poorer teams."}'::jsonb, '{"answer": true, "explain": "Cost is the main driver of unequal access — richer teams and nations can buy an advantage that poorer ones cannot afford."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:tf:10d55d7d', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'tf', 'tf', 1, '{"question": "Availability and affordability mean exactly the same thing."}'::jsonb, '{"answer": false, "explain": "Affordability is about price; availability is about whether the technology can be obtained at all, even with money to spend."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:tf:831ea52d', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'tf', 'tf', 1, '{"question": "As sports technology advances, its cost usually falls, making it cheaper for everyone straight away."}'::jsonb, '{"answer": false, "explain": "Newer technology tends to stay expensive or get more costly, not cheaper, which keeps affordability a live problem."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:tf:b4bc3bac', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'tf', 'tf', 1, '{"question": "Officiating technology can reduce the flow of a game because checking a decision often causes a stoppage."}'::jsonb, '{"answer": true, "explain": "Reviews take time, and that pause interrupts the natural rhythm and momentum of play."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:tf:9a1a08c1', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'tf', 'tf', 1, '{"question": "An official who is ''over-influenced'' by technology always ignores what the technology shows."}'::jsonb, '{"answer": false, "explain": "Over-influenced means the opposite — trusting the technology''s output as automatically correct, even beyond its real limits."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:tf:126d0cad', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'tf', 'tf', 1, '{"question": "Technology can sometimes give the best-funded performers an advantage that has nothing to do with their actual ability."}'::jsonb, '{"answer": true, "explain": "That is the unequal-access problem — the advantage comes from money, not from greater skill or effort."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:learn:ddbac561', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'learn', 'mcq', 1, '{"readingTitle": "Unequal access and rising cost", "reading": "<h4>Not every team can afford the same kit</h4>\n<ul>\n<li>New technology is usually <strong>expensive</strong> when it first appears — cameras, sensors, materials and the software behind them all cost money to develop and buy.</li>\n<li>That cost creates <strong>unequal access</strong>: a wealthy club or a wealthy nation can buy the newest equipment, while a poorer club or nation cannot. The richer side then gains an <strong>advantage</strong> that has nothing to do with the players'' actual ability.</li>\n<li>Example: a well-funded cycling team can afford aerodynamic skinsuits and custom-built bike frames that a smaller national team simply cannot buy, so the smaller team competes at a disadvantage before the race even starts.</li>\n</ul>\n<h4>Cost keeps climbing</h4>\n<ul>\n<li>As technology advances, each new version tends to cost <strong>more</strong>, not less — governing bodies, clubs and venues have to keep spending to stay up to date.</li>\n<li>That spending has to come from somewhere: often ticket prices, membership fees or grassroots budgets, which can mean less money reaching participation at the bottom of the sport.</li>\n</ul>", "question": "Why can new sports technology create unequal access between teams or nations?", "options": ["Because all governing bodies are legally required to share every new invention with every other nation immediately", "Because it is usually expensive, so only wealthier teams or nations can afford to buy and benefit from it", "Because officials will not allow poorer teams to use any technology at all under any circumstances", "Because technology never actually improves a team''s performance in any measurable way"]}'::jsonb, '{"answer": 1, "explain": "New technology tends to be costly, so wealthier teams and nations can buy an advantage that poorer ones cannot afford — that is the unequal-access problem."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:learn:a8283b11', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'learn', 'mcq', 1, '{"readingTitle": "Availability and affordability problems", "reading": "<h4>Two related but different problems</h4>\n<ul>\n<li><strong>Affordability</strong> is about price — a club, school or individual simply cannot pay for the technology.</li>\n<li><strong>Availability</strong> is about supply — even a club that could pay might not be able to get hold of the technology at all, because it is rare, still being trialled, or only used at the very top level of the sport.</li>\n<li>Example: goal-line technology is standard in a top professional football league, but a grassroots Sunday league pitch is unlikely to ever have it — the cost of installing and running the cameras and sensors makes it completely unavailable at that level.</li>\n</ul>\n<h4>Why this matters for participation and fairness</h4>\n<ul>\n<li>If only elite performers ever experience a piece of technology (say, an altitude training chamber or a biomechanics lab), then talented performers without access to it can be left behind, even if they train just as hard.</li>\n<li>This links back to unequal access: cost and availability together mean that technology can widen the gap between the best-funded performers and everyone else, rather than making competition fairer.</li>\n</ul>", "question": "A grassroots pitch cannot get goal-line technology installed at any price because hardly any suppliers offer it at that level. This is mainly a problem of...", "options": ["officiating bias shown specifically and deliberately against smaller, lower-funded grassroots teams", "availability, since the technology is not accessible at that level regardless of budget", "the rules of the sport banning grassroots technology outright", "player fitness rather than technology at all"]}'::jsonb, '{"answer": 1, "explain": "Availability is about the technology simply not being obtainable at that level, which is different from affordability (being too expensive but technically obtainable)."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:learn:37c574ff', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'learn', 'mcq', 1, '{"readingTitle": "Slowing the game down and over-relying on the decision", "reading": "<h4>Reduced flow of the game</h4>\n<ul>\n<li>Officiating technology (such as a video review) usually means the game must <strong>stop</strong> while the check happens. That stoppage breaks up the natural rhythm, or <strong>flow</strong>, of the contest.</li>\n<li>Example: a rugby referee sending a decision \"upstairs\" to the Television Match Official can pause play for over a minute, cooling down the crowd''s atmosphere and interrupting the momentum of the team that was attacking.</li>\n<li>The more often technology is used to check decisions, the more often the game is interrupted — so a technology that improves accuracy can still be criticised for making the contest less enjoyable to play and to watch.</li>\n</ul>\n<h4>Over-influenced officials</h4>\n<ul>\n<li>A separate problem: officials can become <strong>over-reliant</strong> on technology, treating what the screen or sensor shows as automatically correct, even when the technology does not capture the full picture or the correct interpretation of the rule.</li>\n<li>Example: a football assistant referee might wait for a marginal offside decision to be confirmed by the technology instead of trusting their own read of the passage of play, even in situations the technology was never designed to judge precisely.</li>\n<li>The exam skill: don''t just say \"technology causes problems\" — <strong>name the specific negative</strong> (unequal access, cost, availability, reduced flow, over-reliance) and back it with a sport-specific example.</li>\n</ul>", "question": "Which of these best describes ''reduced flow of the game'' as a negative effect of technology?", "options": ["Officiating technology can cause stoppages that interrupt the natural rhythm of play", "Technology always makes every single match finish far more quickly than it ever did before it existed", "Players become less fit because technology does the exercise for them", "Spectators are no longer allowed to watch matches that use technology"]}'::jsonb, '{"answer": 0, "explain": "Checks and reviews take time, and that stoppage interrupts the momentum and rhythm of the contest — that is what ''reduced flow'' means."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:misc:03b2378a', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Technology in sport only ever has positive effects — more accuracy, better performance, nothing to worry about.</p><p><strong>✅ The correct idea:</strong> The specification specifically tests the NEGATIVES too. Unequal access, rising cost, availability/affordability problems, reduced flow of the game, and officials becoming over-influenced by technology are all genuine downsides, even where the technology also helps. A balanced exam answer weighs both sides.</p>", "question": "Which of these is a genuine negative effect the specification expects you to know?", "options": ["Technology always makes officiating completely free of charge for every club", "Unequal access can give wealthier teams or nations an advantage", "Technology has literally no effect on the game whatsoever", "Every spectator always prefers a game with zero technology involved"]}'::jsonb, '{"answer": 1, "explain": "Unequal access is one of the named negatives — cost creates an advantage that has nothing to do with ability."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:misc:dee34c1c', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Affordability and availability are just two words for the same problem.</p><p><strong>✅ The correct idea:</strong> They are related but different. Affordability is about PRICE — a club cannot pay for it. Availability is about SUPPLY — even with money, the technology might not be offered at that level at all. A grassroots pitch may not get goal-line technology at any price, which is an availability problem, not just a cost one.</p>", "question": "A club has the budget to buy a technology, but no supplier will sell it at that level. This is mainly a problem of...", "options": ["affordability", "availability", "officiating bias", "player motivation"]}'::jsonb, '{"answer": 1, "explain": "Having the money but no way to obtain the technology is an availability problem, distinct from affordability."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:misc:48515744', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A video review stopping play is only ever a good thing, because it makes the decision more accurate.</p><p><strong>✅ The correct idea:</strong> Accuracy and flow are a genuine trade-off. A review can improve the accuracy of a decision while still damaging the flow of the game, because play has to stop while it happens. Good exam answers can hold both ideas at once, rather than treating the stoppage as automatically worth it.</p>", "question": "Why can a review that improves accuracy still be criticised?", "options": ["Because it can reduce the flow of the game by causing a stoppage", "Because accurate decisions are against the official rules of every sport", "Because reviews are always slower than officials without any technology at all", "Because spectators are not allowed to watch a review taking place"]}'::jsonb, '{"answer": 0, "explain": "The trade-off is flow versus accuracy — a stoppage to check a decision interrupts the rhythm of play even if it gets the call right."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:tips:eb10023e', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words and mark tariffs for this topic", "reading": "<p>Negative-effects questions scale with the command word and the marks available:</p>\n<ul>\n<li><strong>State / Identify [1]</strong> — name one negative, nothing more. \"State one negative effect of using technology in sport\" = a single named point.</li>\n<li><strong>Explain [2–4]</strong> — name the negative, then give the reason or the sport-specific example that shows you understand it. Two linked points, or one point developed with an example, usually matches a [2] tariff.</li>\n<li><strong>Discuss / Evaluate [8]</strong> — cover more than one negative, apply them to the scenario, and weigh them against a positive before reaching a judgement. A list of negatives with no weighing rarely leaves Band 1.</li>\n</ul>\n<p><strong>Read the tariff before you write</strong> — a [2] question does not need five points, and an [8] question needs far more than a list.</p>", "question": "A question asks ''State one negative effect of technology in sport [1]''. What is the safest answer?", "options": ["A single named negative effect", "A full paragraph covering every negative you know", "Two negatives explained in detail", "A description of a positive effect instead"]}'::jsonb, '{"answer": 0, "explain": "''State'' + [1] wants one named point — writing more wastes time without earning extra marks."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:tips:376bea0e', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'tips', 'mcq', 1, '{"readingTitle": "tip — Always attach a named-sport example", "reading": "<p>A negative named on its own is thin. Build every point as <strong>negative → named sport → what actually happens</strong>:</p>\n<ul>\n<li><strong>❌ weak:</strong> \"Technology costs a lot of money.\"</li>\n<li><strong>✅ strong:</strong> \"In cycling, aerodynamic equipment is expensive, so a well-funded team can afford gains a smaller national team cannot, giving them an advantage unrelated to ability.\"</li>\n</ul>\n<p>In <strong>Section B</strong>, take the example from the scenario you are given rather than a general one you already knew.</p>", "question": "Why does naming a specific sport strengthen an answer about a negative effect of technology?", "options": ["It shows how the negative actually plays out in a real situation", "It is required purely to fill up space on the page", "It completely replaces the need to ever name the negative effect at all anywhere in the answer", "It is only needed in Section C and never elsewhere"]}'::jsonb, '{"answer": 0, "explain": "A concrete sporting example demonstrates real understanding of how the negative effect operates, not just that it exists."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:tips:1ede57cf', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'tips', 'mcq', 1, '{"readingTitle": "tip — Building a balanced Discuss/Evaluate answer", "reading": "<p>An 8-mark Discuss question usually wants you to weigh negatives against at least one positive, then reach a supported judgement.</p>\n<p><strong>Three sentence starters to build the structure:</strong></p>\n<ul>\n<li>\"One negative effect is… which affects [named sport] because…\"</li>\n<li>\"However, technology also… which is a genuine benefit because…\"</li>\n<li>\"Overall, the negatives outweigh/are outweighed by the positives because…\"</li>\n</ul>\n<p>Never stop at a list — the top band needs the weighing and the final judgement, not just more points.</p>", "question": "What usually separates a top-band Discuss answer from a middle-band one on this topic?", "options": ["Writing about a much longer list of negatives with no weighing", "Weighing negatives against positives and reaching a justified judgement", "Only ever mentioning negative effects and ignoring positives completely", "Repeating the same point using slightly different wording each time"]}'::jsonb, '{"answer": 1, "explain": "Top-band answers weigh both sides and land on a justified judgement — a longer list alone does not move up a band."}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:fib:66698280', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'fib', 'fib', 1, '{"question": "Expensive new technology can create _____ access, since only wealthier teams or nations can afford it.", "blankOptions": {"B1": ["flow", "cost", "affordability", "unequal"]}}'::jsonb, '{"blanks": {"B1": "unequal"}}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:fib:692b409d', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'fib', 'fib', 1, '{"question": "The _____ of new sports technology tends to keep rising as it advances.", "blankOptions": {"B1": ["flow", "cost", "affordability", "availability"]}}'::jsonb, '{"blanks": {"B1": "cost"}}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:fib:8830a1b2', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'fib', 'fib', 1, '{"question": "A club that cannot pay for technology has an _____ problem.", "blankOptions": {"B1": ["affordability", "availability", "unequal", "cost"]}}'::jsonb, '{"blanks": {"B1": "affordability"}}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:fib:5117665c', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'fib', 'fib', 1, '{"question": "A club that cannot obtain a technology at all, whatever its budget, faces an _____ problem.", "blankOptions": {"B1": ["affordability", "availability", "flow", "unequal"]}}'::jsonb, '{"blanks": {"B1": "availability"}}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:fib:5deb6dfa', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'fib', 'fib', 1, '{"question": "Video review stoppages can reduce the _____ of the game by interrupting its rhythm.", "blankOptions": {"B1": ["availability", "cost", "unequal", "flow"]}}'::jsonb, '{"blanks": {"B1": "flow"}}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:match:08694085', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Unequal access”?", "options": ["Newer sports technology tends to be expensive, and cost often keeps rising over time", "A club or performer cannot obtain the technology at all, regardless of budget", "A club or performer cannot pay the price of the technology", "Wealthier teams or nations can afford technology that poorer ones cannot, gaining an advantage"]}'::jsonb, '{"answer": 3, "explain": "“Unequal access” means: Wealthier teams or nations can afford technology that poorer ones cannot, gaining an advantage"}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:match:13fa652a', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Increased cost”?", "options": ["A club or performer cannot obtain the technology at all, regardless of budget", "Newer sports technology tends to be expensive, and cost often keeps rising over time", "Officiating technology can cause stoppages that break up the rhythm of play", "A club or performer cannot pay the price of the technology"]}'::jsonb, '{"answer": 1, "explain": "“Increased cost” means: Newer sports technology tends to be expensive, and cost often keeps rising over time"}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:match:4d2ddd06', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Affordability”?", "options": ["Officials treat technology''s output as automatically correct, even outside its real limits", "Officiating technology can cause stoppages that break up the rhythm of play", "Newer sports technology tends to be expensive, and cost often keeps rising over time", "A club or performer cannot pay the price of the technology"]}'::jsonb, '{"answer": 3, "explain": "“Affordability” means: A club or performer cannot pay the price of the technology"}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:match:a51434e1', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Availability”?", "options": ["A club or performer cannot pay the price of the technology", "A club or performer cannot obtain the technology at all, regardless of budget", "Newer sports technology tends to be expensive, and cost often keeps rising over time", "Officiating technology can cause stoppages that break up the rhythm of play"]}'::jsonb, '{"answer": 1, "explain": "“Availability” means: A club or performer cannot obtain the technology at all, regardless of budget"}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:match:f2245858', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Reduced flow of the game”?", "options": ["Officiating technology can cause stoppages that break up the rhythm of play", "Wealthier teams or nations can afford technology that poorer ones cannot, gaining an advantage", "A club or performer cannot pay the price of the technology", "A club or performer cannot obtain the technology at all, regardless of budget"]}'::jsonb, '{"answer": 0, "explain": "“Reduced flow of the game” means: Officiating technology can cause stoppages that break up the rhythm of play"}'::jsonb),
('sport-studies:5-2-2-negative-effects-of-technology:match:0185b782', 'sport-studies', 'sport-studies:5-2-2-negative-effects-of-technology', '5.2.2 Negative Effects of Technology', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Over-influenced officials”?", "options": ["Officials treat technology''s output as automatically correct, even outside its real limits", "A club or performer cannot obtain the technology at all, regardless of budget", "Newer sports technology tends to be expensive, and cost often keeps rising over time", "Officiating technology can cause stoppages that break up the rhythm of play"]}'::jsonb, '{"answer": 0, "explain": "“Over-influenced officials” means: Officials treat technology''s output as automatically correct, even outside its real limits"}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:exam:65707bb9', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is a genuine negative effect of technology on the spectator experience?", "options": ["A long wait for a video review can break the crowd''s atmosphere and tension", "Big screens always guarantee that every decision given is completely correct", "Broadcast graphics remove the need for any spectator to understand the rules", "Extra camera angles make it impossible for any home viewer to enjoy a match"], "hint": "Think about which option is a genuine, realistic downside rather than an exaggerated claim.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — A long wait for a video review can break the crowd''s atmosphere and tension.</strong></p>\n<ul>\n<li>This is a genuine negative effect: the delay interrupts the pace of the contest and quietens the crowd.</li>\n<li>The other options overstate what technology can do (guaranteeing correctness, removing the need to understand rules, or making enjoyment \"impossible\"), which is not accurate.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:mcq:c2b4aa8f', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'mcq', 'mcq', 1, '{"question": "What is the main benefit of a big screen replay for spectators inside a stadium?", "options": ["It lets fans see the same replay evidence as the match officials, which builds trust in the decision", "It gives the crowd a formal vote that can overturn any refereeing decision it strongly dislikes, no matter what", "It ends the referee''s involvement in the game completely from that moment onwards", "It exists only to fill the silence while the refreshment stalls remain open for business"]}'::jsonb, '{"answer": 0, "explain": "Seeing the same evidence as the officials helps fans understand a decision and builds trust. It does not give the crowd a vote, remove the referee, or exist only to sell refreshments."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:mcq:7b1b52eb', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'mcq', 'mcq', 1, '{"question": "Why can watching a match at home now be a richer experience than in the past?", "options": ["Broadcast graphics and statistics on screen help viewers understand the contest in far more depth", "Home viewers are given a private link that lets them personally overrule any decision that is given", "Every match can now legally only be watched on a television screen and nowhere else at all", "Extra camera angles are shown, but broadcasters are never permitted to include any replay"]}'::jsonb, '{"answer": 0, "explain": "Extra statistics and graphics genuinely add understanding for a home audience. Viewers cannot overrule decisions, matches are not television-only, and replays are a normal part of modern broadcasts."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:mcq:0a3aa2b9', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'mcq', 'mcq', 1, '{"question": "What is a genuine negative effect of a long wait for a technology-based decision?", "options": ["It can break the atmosphere and tension that the crowd had built up before the review", "It always guarantees that the original, on-field decision will be proven completely correct", "It permanently removes the need for any official to be present at future matches", "It stops every single spectator from being able to follow the rest of that match"]}'::jsonb, '{"answer": 0, "explain": "A long delay genuinely interrupts a stadium''s pace and quietens the crowd. It does not guarantee the original decision was right, remove officials, or stop fans following the rest of the game."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:mcq:c03d80c2', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'mcq', 'mcq', 1, '{"question": "How can over-reliance on big screens reduce a spectator''s experience?", "options": ["Spectators can end up watching the replay so closely that they miss the next live action", "Spectators are legally required to look only at the pitch and never at any screen", "Screens automatically make every single crowd completely silent for the rest of the match", "Screens remove all further need for spectators to buy a ticket in future"]}'::jsonb, '{"answer": 0, "explain": "Staring at a replay can mean missing what happens live next, which is the real downside. There is no legal rule about where fans look, and screens do not silence crowds or remove the need for tickets."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:mcq:1a129015', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'mcq', 'mcq', 1, '{"question": "How can the cost of spectator technology affect fans?", "options": ["It can be passed on through higher ticket prices or a paid subscription for extra footage", "It always reduces every single ticket price at every stadium that installs brand new technology", "It has no effect at all on prices because governing bodies fully cover every cost", "It only affects players'' wages and never touches anything that a spectator pays"]}'::jsonb, '{"answer": 0, "explain": "Clubs and broadcasters often recover the cost of technology through fans'' ticket or subscription prices. It does not reduce prices, get fully covered elsewhere, or avoid spectators altogether."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:mcq:63fb68b5', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'mcq', 'mcq', 1, '{"question": "What does it mean to judge the ''suitability'' of technology for a fixture?", "options": ["Weighing whether the benefit of a review is worth its cost and delay for that particular event", "Assuming every single fixture, however small in size, needs the exact same amount of review technology", "Deciding that only the most expensive technology available can ever be worth using", "Ignoring cost completely, since delay is the only thing that ever matters to a crowd"]}'::jsonb, '{"answer": 0, "explain": "Suitability means balancing the benefit of getting a decision right against the cost and delay involved for that event. It is not about using maximum technology everywhere, or ignoring cost."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:tf:5b96c16b', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'tf', 'tf', 1, '{"question": "Big screen replays can help spectators understand why a decision was given."}'::jsonb, '{"answer": true, "explain": "Seeing the same evidence as the officials is exactly why replays help spectators follow and understand the game."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:tf:e09ce1fa', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'tf', 'tf', 1, '{"question": "Watching a match at home has become richer partly because of on-screen statistics and graphics."}'::jsonb, '{"answer": true, "explain": "Broadcast graphics and stats add detail a stadium seat cannot give, which is a genuine positive effect for home viewers."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:tf:d50a3704', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'tf', 'tf', 1, '{"question": "A long wait for a technology-based decision has no effect on a stadium''s atmosphere."}'::jsonb, '{"answer": false, "explain": "A long review genuinely breaks the crowd''s atmosphere and interrupts the pace of the contest — it is a real negative effect."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:tf:525a2a10', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'tf', 'tf', 1, '{"question": "The cost of installing review technology can never affect ticket or subscription prices."}'::jsonb, '{"answer": false, "explain": "Clubs and broadcasters often pass the cost of technology on through higher ticket prices or paid subscriptions."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:tf:687e47d9', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'tf', 'tf', 1, '{"question": "Every sport and venue needs exactly the same amount of review technology, regardless of cost."}'::jsonb, '{"answer": false, "explain": "Suitability means weighing the benefit against the cost and delay for that event — a small fixture may not need what a major final does."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:tf:f053f02b', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'tf', 'tf', 1, '{"question": "Some fans feel a contest can feel less \"human\" when every close moment is checked by technology."}'::jsonb, '{"answer": true, "explain": "This is a genuine criticism — some spectators feel the game loses spontaneity when officials'' instant judgement is replaced by a pause for review."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:learn:010341f7', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'learn', 'mcq', 1, '{"readingTitle": "Technology and the crowd inside the stadium — the positives", "reading": "<h4>Understanding decisions, not just guessing</h4>\n<ul>\n<li>Many sports now show a <strong>technology-based decision</strong> on the stadium''s big screen — for example a video review of a contested goal, or a graphic showing whether a shot landed in or out.</li>\n<li>Seeing the same replay the officials used helps spectators <strong>follow the action and understand why a decision was given</strong>, instead of hearing an announcement with no evidence behind it.</li>\n<li>This makes big decisions feel more open and fair, because the whole crowd can judge the evidence for itself rather than simply trusting an official''s word.</li>\n</ul>\n<h4>Big screens do more than show replays</h4>\n<ul>\n<li>Big screens can also show <strong>scores and stats from other fixtures</strong>, close-up replays of skilful moments, and information that keeps spectators engaged even during a stoppage in play.</li>\n<li><strong>Named example:</strong> at a football match, a big screen showing the video-review footage of a disputed goal-line incident lets the crowd see the same picture the video official is using, rather than waiting for an announcement alone.</li>\n</ul>", "question": "What does a stadium big screen replay mainly give spectators?", "options": ["A guarantee that the crowd''s preferred team will always benefit from the final decision", "The power to personally replace an official who has made an unpopular decision", "The same evidence the officials used, helping them understand why a decision was given", "A permanent recording that spectators are allowed to keep and take home after the match"]}'::jsonb, '{"answer": 2, "explain": "The value of a replay is that it shows fans the evidence behind a decision, building understanding — not favouring a team, replacing officials, or acting as a keepsake."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:learn:b09ee494', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'learn', 'mcq', 1, '{"readingTitle": "Technology and the audience watching from home — the positives", "reading": "<h4>A deeper picture than a stadium seat can give</h4>\n<ul>\n<li>Broadcasters can add <strong>graphics and statistics</strong> to the picture — for example a graphic showing possession, distance covered, or exactly where a ball crossed a line — detail a spectator in a stadium seat cannot see.</li>\n<li>Multiple camera angles and slow-motion replays let a home viewer study a controversial moment from angles the on-field official never had, adding to their understanding and enjoyment of the contest.</li>\n</ul>\n<h4>Named example</h4>\n<ul>\n<li><strong>Ball-tracking technology</strong>, used in sports such as cricket and tennis broadcasts, turns a fast, hard-to-see moment into a clear graphic, so a home viewer can follow a decision as confidently as an expert watching live.</li>\n<li>Overall, this extra layer of detail is one reason many fans say watching from home has become a genuinely richer experience than it used to be.</li>\n</ul>", "question": "Which of these best explains why home viewing has been enhanced by technology?", "options": ["Home viewers now receive a private vote on every contested decision during the game", "Broadcast graphics, statistics and extra camera angles add detail a stadium seat cannot give", "Every home broadcast is now required by law to remove all forms of camera replay", "Home viewers can only ever watch short highlights and are never shown the match as it happens live"]}'::jsonb, '{"answer": 1, "explain": "Extra graphics, stats and camera angles are the genuine reason home viewing has improved — there is no viewer vote, no ban on replays, and live coverage still happens."}'::jsonb),
('sport-studies:5-2-3-technology-and-the-spectator-experience:learn:6f6447e2', 'sport-studies', 'sport-studies:5-2-3-technology-and-the-spectator-experience', '5.2.3 Technology and the Spectator Experience', 'learn', 'mcq', 1, '{"readingTitle": "The negatives — and judging whether technology is \"suitable\"", "reading": "<h4>Waiting breaks the atmosphere</h4>\n<ul>\n<li>A video review can take a minute or more, and that wait can <strong>break the atmosphere and tension</strong> in the stadium — the crowd''s noise dies down and the pace of the contest is interrupted.</li>\n</ul>\n<h4>Screens can distract from the live action</h4>\n<ul>\n<li>Spectators (and sometimes commentators) can end up staring at a screen replay of the last incident and <strong>miss the next passage of play</strong> happening live in front of them — an over-reliance on screens.</li>\n</ul>\n<h4>Cost</h4>\n<ul>\n<li>Cameras, review systems and big screens are expensive to install and run. That cost can be passed on through <strong>higher ticket prices or paid subscription tiers</strong>, which can price some spectators out altogether.</li>\n</ul>\n<h4>Feeling less \"human\"</h4>\n<ul>\n<li>Some fans feel a contest loses some of its human character when every close moment is paused for a technological check, rather than trusting an official''s instant judgement.</li>\n</ul>\n<h4>Suitability — the evaluation skill</h4>\n<ul>\n<li>Not every sport, venue or decision needs the same level of technology. The real question is whether a review is <strong>important enough to justify its cost and delay</strong> — a major final may justify it more than a small local fixture.</li>\n<li><strong>Named example:</strong> a small, non-televised local match is unlikely to have (or need) the same big-screen review system as a major televised final, because the cost would not be justified by the benefit.</li>\n</ul>", "question": "Judging the \"suitability\" of technology for the spectator experience mainly means...?", "options": ["Assuming every single venue must install the most expensive technology that is currently available", "Ignoring how much a review costs, since only the delay it causes really matters", "Deciding that no sport should ever use any form of review technology at all", "Weighing whether the benefit of using it is worth its cost and delay for that event"]}'::jsonb, '{"answer": 3, "explain": "Suitability is about weighing benefit against cost and delay for that particular event — not assuming maximum technology everywhere, ignoring cost, or banning it outright."}'::jsonb)
